#!/bin/bash
# Windrose Installation Script
# Image: ghcr.io/pterodactyl/installers:debian
echo "    __  __                _____                ";
echo "   / / / /_  ______  ___ / ___/___  ______   __";
echo "  / /_/ / / / / __ \\/ _ \\\\__ \\/ _ \\/ ___/ | / /";
echo " / __  / /_/ / /_/ /  __/__/ /  __/ /   | |/ / ";
echo "/_/ /_/\\__, / .___/\\___/____/\\___/_/    |___/  ";
echo "      /____/_/                                 ";
echo "Windrose Installer v0.0.5";
apt-get update
apt-get install -y curl ca-certificates lib32gcc-s1 tar

mkdir -p /mnt/server/steamcmd
cd /mnt/server/steamcmd

echo "Downloading SteamCMD..."
curl -sSL -o steamcmd.tar.gz https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz
tar -xzvf steamcmd.tar.gz
rm steamcmd.tar.gz

echo "Installing Windrose Dedicated Server (App ID 4129620)..."
mkdir -p /mnt/server

STEAM_LOGIN="anonymous"
if [ -n "${STEAM_USER}" ] && [ "${STEAM_USER}" != "null" ]; then
    STEAM_LOGIN="${STEAM_USER} ${STEAM_PASS}"
fi

./steamcmd.sh \
    +force_install_dir /mnt/server \
    +login ${STEAM_LOGIN} \
    +app_update 4129620 validate \
    +quit

echo "Fixing permissions..."
chown -R 1000:1000 /mnt/server


echo "    __  __                _____                ";
echo "   / / / /_  ______  ___ / ___/___  ______   __";
echo "  / /_/ / / / / __ \\/ _ \\\\__ \\/ _ \\/ ___/ | / /";
echo " / __  / /_/ / /_/ /  __/__/ /  __/ /   | |/ / ";
echo "/_/ /_/\\__, / .___/\\___/____/\\___/_/    |___/  ";
echo "      /____/_/                                 ";
echo "Installation complete."
